### Implementation Code
```python
# url_shortener.py
import hashlib
import urllib.parse
from threading import Lock
from urllib.parse import urlparse

class ThreadSafeDict:
    def __init__(self):
        self.dict = {}
        self.lock = Lock()

    def get(self, key):
        with self.lock:
            return self.dict.get(key)

    def __setitem__(self, key, value):
        with self.lock:
            self.dict[key] = value

class URLValidator:
    def validate_url(self, url):
        try:
            result = urlparse(url)
            return all([result.scheme, result.netloc])
        except ValueError:
            return False

class HashGenerator:
    def generate_hash(self, url):
        return hashlib.sha256(url.encode()).hexdigest()[:6]

class CollisionDetector:
    def detect_collision(self, hash_value, url_map):
        return hash_value in url_map

class URLShortener:
    def __init__(self):
        self.url_map = ThreadSafeDict()
        self.hash_generator = HashGenerator()
        self.url_validator = URLValidator()
        self.collision_detector = CollisionDetector()

    def shorten_url(self, long_url):
        if not self.url_validator.validate_url(long_url):
            raise ValueError("Invalid URL")

        hash_value = self.hash_generator.generate_hash(long_url)
        if self.collision_detector.detect_collision(hash_value, self.url_map.get):
            raise ValueError("Collision detected")

        self.url_map[hash_value] = long_url
        return f"http://short.url/{hash_value}"

    def get_original_url(self, short_url):
        hash_value = short_url.split("/")[-1]
        return self.url_map.get(hash_value)

    def validate_url(self, url):
        return self.url_validator.validate_url(url)

def main():
    shortener = URLShortener()
    long_url = "https://www.example.com"
    short_url = shortener.shorten_url(long_url)
    print(f"Short URL: {short_url}")
    print(f"Original URL: {shortener.get_original_url(short_url)}")

if __name__ == "__main__":
    main()
```

This implementation provides the following functionality:

1.  **URL Shortening:** The `shorten_url` method generates a unique hash for a given URL and returns the shortened URL.
2.  **Reverse Lookup:** The `get_original_url` method retrieves the original URL from a given shortened URL.
3.  **Collision Detection:** The `detect_collision` method checks if a generated hash already exists in the URL map.
4.  **Input Validation:** The `validate_url` method checks if a given URL is valid.
5.  **Thread Safety:** The `ThreadSafeDict` class provides a thread-safe dictionary for storing the URL mappings.

