# url_shortener.py
import hashlib
import urllib.parse
from threading import Lock
from urllib.parse import urlparse

class ThreadSafeDict:
    def __init__(self):
        self.dict = {}
        self.lock = Lock()

    def get(self, key):
        with self.lock:
            return self.dict.get(key)

    def __setitem__(self, key, value):
        with self.lock:
            self.dict[key] = value

    def __contains__(self, key):
        with self.lock:
            return key in self.dict

class URLValidator:
    def validate_url(self, url):
        try:
            result = urlparse(url)
            return all([result.scheme, result.netloc])
        except ValueError:
            return False

class HashGenerator:
    def generate_hash(self, url):
        return hashlib.sha256(url.encode()).hexdigest()[:6]

class CollisionDetector:
    def detect_collision(self, hash_value, url_map):
        return hash_value in url_map

class URLShortener:
    def __init__(self):
        self.url_map = ThreadSafeDict()
        self.hash_generator = HashGenerator()
        self.url_validator = URLValidator()
        self.collision_detector = CollisionDetector()

    def shorten_url(self, long_url):
        if not self.url_validator.validate_url(long_url):
            return None

        hash_value = self.hash_generator.generate_hash(long_url)
        if self.collision_detector.detect_collision(hash_value, self.url_map):
            return None

        self.url_map[hash_value] = long_url
        return f"http://short.url/{hash_value}"

    def get_original_url(self, short_url):
        hash_value = short_url.split("/")[-1]
        return self.url_map.get(hash_value)

    def validate_url(self, url):
        return self.url_validator.validate_url(url)

def main():
    shortener = URLShortener()
    long_url = "https://www.example.com"
    short_url = shortener.shorten_url(long_url)
    if short_url is not None:
        print(f"Short URL: {short_url}")
        print(f"Original URL: {shortener.get_original_url(short_url)}")
    else:
        print("Failed to shorten URL")

if __name__ == "__main__":
    main()
```

