        with self.assertRaises(ValueError):
            TokenBucket(5, -10)

    def test_token_bucket_consume_invalid_tokens(self):
        token_bucket = TokenBucket(5, 10)
        with self.assertRaises(ValueError):
            token_bucket.consume_tokens(-5)

    def test_thread_safety(self):
        rate_limiter = RateLimiter(5, 10)
        threads = []

        def test_allow():
            for _ in range(10):
                rate_limiter.allow()

        for _ in range(10):
            thread = threading.Thread(target=test_allow)
            thread.start()
            threads.append(thread)

        for thread in threads:
            thread.join()

        self.assertLessEqual(rate_limiter.token_bucket.get_tokens(), 0)

