```python
import threading
import heapq
import time
from functools import wraps

class Task:
    def __init__(self, id, priority, func, *args, **kwargs):
        self.id = id
        self.priority = priority
        self.func = func
        self.args = args
        self.kwargs = kwargs
        self.status = 'pending'
        self.retries = 0

    def execute(self):
        try:
            self.func(*self.args, **self.kwargs)
            self.status = 'completed'
        except Exception as e:
            self.status = 'failed'
            self.retries += 1
            raise e

class TaskQueue:
    def __init__(self):
        self.queue = []
        self.lock = threading.Lock()

    def add_task(self, task):
        with self.lock:
            heapq.heappush(self.queue, (task.priority, task))
            print(f'Task {task.id} added to queue')

    def get_task(self):
        with self.lock:
            if not self.queue:
                return None
            _, task = heapq.heappop(self.queue)
            return task

class WorkerThread(threading.Thread):
    def __init__(self, task_queue):
        super().__init__()
        self.task_queue = task_queue
        self.stop_event = threading.Event()

    def run(self):
        while not self.stop_event.is_set():
            task = self.task_queue.get_task()
            if task:
                task.status = 'running'
                try:
                    task.execute()
                except Exception as e:
                    print(f'Task {task.id} failed with error: {e}')
                    if task.retries < 3:  # max retries
                        self.task_queue.add_task(task)
                    else:
                        print(f'Task {task.id} failed after max retries')
            else:
                time.sleep(1)

    def stop(self):
        self.stop_event.set()

def retry(max_retries):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            retries = 0
            while retries < max_retries:
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    print(f'Error: {e}')
                    retries += 1
            raise Exception(f'Max retries exceeded')
        return wrapper
    return decorator

# Example usage:
task_queue = TaskQueue()
worker = WorkerThread(task_queue)
worker.start()

@retry(3)
def example_task():
    print('Example task executed')
    raise Exception('Example error')

task = Task(1, 1, example_task)
task_queue.add_task(task)

time.sleep(10)
worker.stop()
worker.join()

# Unit tests
import unittest

class TestTaskQueue(unittest.TestCase):
    def test_add_task(self):
        task_queue = TaskQueue()
        task = Task(1, 1, lambda: None)
        task_queue.add_task(task)
        self.assertEqual(task_queue.get_task(), task)

    def test_get_task(self):
        task_queue = TaskQueue()
        task = Task(1, 1, lambda: None)
        task_queue.add_task(task)
        self.assertEqual(task_queue.get_task(), task)

    def test_worker_thread(self):
        task_queue = TaskQueue()
        worker = WorkerThread(task_queue)
        task = Task(1, 1, lambda: None)
        task_queue.add_task(task)
        worker.start()
        time.sleep(1)
        worker.stop()
        worker.join()
        self.assertEqual(task.status, 'running')

    def test_retry_decorator(self):
        @retry(3)
        def example_task():
            raise Exception('Example error')

        with self.assertRaises(Exception):
            example_task()

if __name__ == '__main__':
    unittest.main()
```

