```python
import pandas as pd
import json

# Data Reader
class DataReader:
    def __init__(self, schema):
        self.schema = schema

    def read_csv(self, file_path):
        try:
            data = pd.read_csv(file_path)
            self.validate_schema(data)
            return data
        except Exception as e:
            raise SchemaValidationError(str(e))

    def validate_schema(self, data):
        # Perform schema validation using the pandas library
        for column, data_type in self.schema.items():
            if column not in data.columns:
                raise SchemaValidationError(f"Column '{column}' is missing from the data")
            if not pd.api.types.is_numeric_dtype(data[column]) and data_type == int:
                raise SchemaValidationError(f"Column '{column}' is not of type int")
            if not pd.api.types.is_string_dtype(data[column]) and data_type == str:
                raise SchemaValidationError(f"Column '{column}' is not of type str")

# Schema Validation Error
class SchemaValidationError(Exception):
    pass

# Transformation Chain
class TransformationChain:
    def __init__(self):
        self.transformations = []

    def add_transformation(self, transformation):
        self.transformations.append(transformation)

    def apply_transformations(self, data):
        for transformation in self.transformations:
            data = transformation.apply(data)
        return data

# Plugin Interface
class PluginInterface:
    def apply(self, data):
        pass

# Filter Plugin
class FilterPlugin(PluginInterface):
    def __init__(self, condition):
        self.condition = condition

    def apply(self, data):
        return data[self.condition]

# Map Plugin
class MapPlugin(PluginInterface):
    def __init__(self, mapping):
        self.mapping = mapping

    def apply(self, data):
        return data.apply(self.mapping)

# Aggregate Plugin
class AggregatePlugin(PluginInterface):
    def __init__(self, aggregation):
        self.aggregation = aggregation

    def apply(self, data):
        return data.agg(self.aggregation)

# Plugin Registry
class PluginRegistry:
    def __init__(self):
        self.plugins = {}

    def register_plugin(self, plugin_name, plugin):
        self.plugins[plugin_name] = plugin

    def get_plugin(self, plugin_name):
        return self.plugins.get(plugin_name)

# Data Writer
class DataWriter:
    def __init__(self, output_format):
        self.output_format = output_format

    def write_csv(self, data, file_path):
        data.to_csv(file_path, index=False)

    def write_json(self, data, file_path):
        with open(file_path, 'w') as f:
            json.dump(data.to_dict(), f)

# Error Reporter
class ErrorReporter:
    def __init__(self):
        self.error_codes = {}

    def report_error(self, error_code, error_message):
        self.error_codes[error_code] = error_message

# Pipeline
class Pipeline:
    def __init__(self, data_reader, transformation_chain, plugin_registry, data_writer, error_reporter):
        self.data_reader = data_reader
        self.transformation_chain = transformation_chain
        self.plugin_registry = plugin_registry
        self.data_writer = data_writer
        self.error_reporter = error_reporter

    def run(self, file_path, output_file_path):
        try:
            data = self.data_reader.read_csv(file_path)
            data = self.transformation_chain.apply_transformations(data)
            if self.data_writer.output_format == 'csv':
                self.data_writer.write_csv(data, output_file_path)
            elif self.data_writer.output_format == 'json':
                self.data_writer.write_json(data, output_file_path)
        except Exception as e:
            self.error_reporter.report_error('MALFORMED_DATA', str(e))

# Unit Tests
import unittest

class TestDataPipeline(unittest.TestCase):
    def test_data_reader(self):
        data_reader = DataReader({'name': str, 'age': int})
        data = data_reader.read_csv('test.csv')
        self.assertEqual(data.shape[1], 2)

    def test_transformation_chain(self):
        transformation_chain = TransformationChain()
        transformation_chain.add_transformation(lambda x: x * 2)
        data = pd.DataFrame({'x': [1, 2, 3]})
        transformed_data = transformation_chain.apply_transformations(data)
        self.assertEqual(transformed_data['x'].sum(), 12)

    def test_plugin_system(self):
        plugin_registry = PluginRegistry()
        plugin_registry.register_plugin('double', FilterPlugin(lambda x: x > 2))
        plugin = plugin_registry.get_plugin('double')
        data = pd.DataFrame({'x': [1, 2, 3]})
        transformed_data = plugin.apply(data)
        self.assertEqual(transformed_data['x'].sum(), 3)

    def test_data_writer(self):
        data_writer = DataWriter('csv')
        data = pd.DataFrame({'x': [1, 2, 3]})
        data_writer.write_csv(data, 'test.csv')

    def test_error_reporter(self):
        error_reporter = ErrorReporter()
        error_reporter.report_error('MALFORMED_DATA', 'Error message')
        self.assertEqual(error_reporter.error_codes['MALFORMED_DATA'], 'Error message')

if __name__ == '__main__':
