    data_reader = DataReader(schema)
    transformation_chain = TransformationChain()
    plugin_registry = PluginRegistry()
    data_writer = DataWriter('csv')
    error_reporter = ErrorReporter()
    pipeline = Pipeline(data_reader, transformation_chain, plugin_registry, data_writer, error_reporter)

    # Run the pipeline
