```python
import pandas as pd
import json
import csv
import logging
import unittest
from abc import ABC, abstractmethod
from importlib import import_module
import os
import yaml

# Data Reader
class DataReader:
    def __init__(self, schema):
        self.schema = schema
        self.logger = logging.getLogger(__name__)

    def read_csv(self, file_path):
        try:
            data = pd.read_csv(file_path)
            self.validate_schema(data)
            return data
        except Exception as e:
            self.logger.error(f"Failed to read CSV file: {e}")
            raise

    def validate_schema(self, data):
        for column, dtype in self.schema.items():
            if column not in data.columns:
                self.logger.error(f"Column '{column}' not found in data")
                raise ValueError(f"Column '{column}' not found in data")
            if data[column].dtype != dtype:
                self.logger.error(f"Column '{column}' has incorrect data type")
                raise ValueError(f"Column '{column}' has incorrect data type")


# Transformation Interface
class Transformation(ABC):
    @abstractmethod
    def apply(self, data):
        pass


# Filtering Transformation
class FilteringTransformation(Transformation):
    def __init__(self, filter_func):
        self.filter_func = filter_func
        self.logger = logging.getLogger(__name__)

    def apply(self, data):
        try:
            return data[self.filter_func(data)]
        except Exception as e:
            self.logger.error(f"Failed to apply filtering transformation: {e}")
            raise


# Mapping Transformation
class MappingTransformation(Transformation):
    def __init__(self, mapping_func):
        self.mapping_func = mapping_func
        self.logger = logging.getLogger(__name__)

    def apply(self, data):
        try:
            return data.apply(self.mapping_func)
        except Exception as e:
            self.logger.error(f"Failed to apply mapping transformation: {e}")
            raise


# Aggregation Transformation
class AggregationTransformation(Transformation):
    def __init__(self, aggregation_func):
        self.aggregation_func = aggregation_func
        self.logger = logging.getLogger(__name__)

    def apply(self, data):
        try:
            return data.agg(self.aggregation_func)
        except Exception as e:
            self.logger.error(f"Failed to apply aggregation transformation: {e}")
            raise


# Transformation Chain
class TransformationChain:
    def __init__(self):
        self.transformations = []
        self.logger = logging.getLogger(__name__)

    def add_transformation(self, transformation):
        self.transformations.append(transformation)

    def apply(self, data):
        try:
            for transformation in self.transformations:
                data = transformation.apply(data)
            return data
        except Exception as e:
            self.logger.error(f"Failed to apply transformation chain: {e}")
            raise


# Plugin System
class PluginSystem:
    def __init__(self):
        self.plugins = {}
        self.logger = logging.getLogger(__name__)

    def register_plugin(self, plugin_name, plugin_module):
        try:
            self.plugins[plugin_name] = import_module(plugin_module)
        except Exception as e:
            self.logger.error(f"Failed to register plugin: {e}")
            raise

    def get_plugin(self, plugin_name):
        try:
            return self.plugins.get(plugin_name)
        except Exception as e:
            self.logger.error(f"Failed to get plugin: {e}")
            raise


# Data Writer
class DataWriter:
    def __init__(self, output_format):
        self.output_format = output_format
        self.logger = logging.getLogger(__name__)

    def write(self, data, file_path):
        try:
            if self.output_format == "csv":
                data.to_csv(file_path, index=False)
            elif self.output_format == "json":
                data.to_json(file_path, orient="records")
            else:
                self.logger.error(f"Invalid output format: {self.output_format}")
                raise ValueError(f"Invalid output format: {self.output_format}")
        except Exception as e:
            self.logger.error(f"Failed to write data: {e}")
            raise


# Pipeline
class Pipeline:
    def __init__(self, config):
        self.config = config
        self.data_reader = DataReader(config["schema"])
        self.transformation_chain = TransformationChain()
        self.plugin_system = PluginSystem()
        self.data_writer = DataWriter(config["output_format"])
        self.logger = logging.getLogger(__name__)

        for transformation in config["transformations"]:
            self.transformation_chain.add_transformation(transformation)

    def run(self, input_file_path, output_file_path):
        try:
            data = self.data_reader.read_csv(input_file_path)
            transformed_data = self.transformation_chain.apply(data)
            self.data_writer.write(transformed_data, output_file_path)
        except Exception as e:
            self.logger.error(f"Failed to run pipeline: {e}")
            raise


# Utils
def validate_schema(data, schema):
    for column, dtype in schema.items():
        if column not in data.columns:
            raise ValueError(f"Column '{column}' not found in data")
        if data[column].dtype != dtype:
            raise ValueError(f"Column '{column}' has incorrect data type")

def apply_transformation(data, func):
    return func(data)


# Config
def get_config(config_file):
    with open(config_file, "r") as f:
        config = yaml.safe_load(f)
    return config


# Unit Tests
class TestDataPipeline(unittest.TestCase):
    def test_data_reader(self):
        schema = {"name": str, "age": int}
        data_reader = DataReader(schema)
        data = pd.DataFrame({"name": ["John", "Jane"], "age": [25, 30]})
        data.to_csv("test.csv", index=False)
        result = data_reader.read_csv("test.csv")
        self.assertIsInstance(result, pd.DataFrame)

    def test_transformation_chain(self):
        transformation_chain = TransformationChain()
        transformation = FilteringTransformation(lambda x: x > 0)
        transformation_chain.add_transformation(transformation)
        data = pd.DataFrame({"values": [1, 2, 3]})
        result = transformation_chain.apply(data)
        self.assertEqual(result["values"].tolist(), [1, 2, 3])

    def test_plugin_system(self):
        plugin_system = PluginSystem()
        plugin_system.register_plugin("test_plugin", "test_plugin_module")
        plugin = plugin_system.get_plugin("test_plugin")
        self.assertIsNotNone(plugin)

    def test_data_writer(self):
        data_writer = DataWriter("csv")
        data = pd.DataFrame({"name": ["John", "Jane"], "age": [25, 30]})
        data_writer.write(data, "test.csv")
        self.assertTrue(os.path.exists("test.csv"))

if __name__ == "__main__":
    # Example usage
    config = get_config("config.yaml")
    pipeline = Pipeline(config)
    pipeline.run("input.csv", "output.csv")

    # Run unit tests
    unittest.main(argv=[''], verbosity=2, exit=False)
