# Unit Tests
import unittest

class TestURLShortener(unittest.TestCase):
    def test_shorten_url(self):
        url_shortener = URLShortener()
        long_url = "https://www.example.com/very/long/url"
        short_url = url_shortener.shorten_url(long_url)
        self.assertEqual(len(short_url), 22)

    def test_reverse_lookup(self):
        url_shortener = URLShortener()
        long_url = "https://www.example.com/very/long/url"
        short_url = url_shortener.shorten_url(long_url)
        self.assertEqual(url_shortener.reverse_lookup(short_url), long_url)

    def test_collision_detection(self):
        url_shortener = URLShortener()
        long_url1 = "https://www.example.com/very/long/url1"
        long_url2 = "https://www.example.com/very/long/url2"
        short_url1 = url_shortener.shorten_url(long_url1)
        short_url2 = url_shortener.shorten_url(long_url2)
        self.assertNotEqual(short_url1, short_url2)

    def test_input_validation(self):
        url_shortener = URLShortener()
        invalid_url = "invalid url"
        with self.assertRaises(ValueError):
            url_shortener.shorten_url(invalid_url)

    def test_thread_safety(self):
        import threading
        url_shortener = URLShortener()
        long_url = "https://www.example.com/very/long/url"
        def shorten_url():
            short_url = url_shortener.shorten_url(long_url)
            self.assertEqual(len(short_url), 22)
        threads = [threading.Thread(target=shorten_url) for _ in range(10)]
        for thread in threads:
            thread.start()
        for thread in threads:
            thread.join()

    def test_empty_url(self):
        url_shortener = URLShortener()
        empty_url = ""
        with self.assertRaises(ValueError):
            url_shortener.shorten_url(empty_url)

    def test_none_url(self):
        url_shortener = URLShortener()
        none_url = None
        with self.assertRaises(ValueError):
            url_shortener.shorten_url(none_url)

if __name__ == "__main__":
    unittest.main()
```

